let inputValues = {};

if (msg.reset === true) {
    // Clear the context and set message counts to 0
    for (let i = 0; i < inputProperties.length; i++) {
        context.set(inputProperties[i], { count: 0, value: null });
    }
} else {
    // Check if the message input has changed
    let inputChanged = false;
    for (let i = 0; i < inputProperties.length; i++) {
        let propName = inputProperties[i];
        if (propName !== "none" && msg.hasOwnProperty(propName)) {
            let propValue = context.get(propName);
            if (propValue !== undefined && msg[propName] !== propValue.value) {
                // Save the current message input values in context
                let count = propValue.count;
                context.set(propName, { count: count + 1, value: msg[propName] });
                inputValues[propName] = msg[propName];
                inputChanged = true;
            }
        }
    }
    if (inputChanged) {
        // Set the input values on the output message
        let outputMsg = Object.assign({}, msg, inputValues);
        // Set the status to "green"
        let statusText = "";
        for (let i = 0; i < inputProperties.length; i++) {
            let propName = inputProperties[i];
            if (propName !== "none") {
                let propValue = context.get(propName);
                if (propValue !== undefined && propValue.value !== null) {
                    let count = propValue.count;
                    statusText += propName + " (" + count + ")";
                    if (i < inputProperties.length - 1) {
                        statusText += ", ";
                    }
                }
            }
        }


        node.status({ fill: "green", shape: "dot", text: statusText });
        // Pass the message to the function output with status
        outputMsg.status = { fill: "green", shape: "dot", text: statusText };
        return outputMsg;


    }
    // Check if there are any values in the context
    let hasContext = false;
    for (let i = 0; i < inputProperties.length; i++) {
        let propName = inputProperties[i];
        if (propName !== "none") {
            let propValue = context.get(propName);
            if (propValue !== undefined && propValue.value !== null) {
                hasContext = true;
                break;
            }
        }
    }


        // Set the status to "red" if there are no values in the context
        if (!hasContext) {
            node.status({ fill: "red", shape: "dot", text: "disconnected" });
            msg.status = { fill: "red", shape: "dot", text: "disconnected" };




    } else {
        // Set the status to "green" if there are values in the context
        let statusText = "";
        for (let i = 0; i < inputProperties.length; i++) {
            let propName = inputProperties[i];
            if (propName !== "none" && context.get(propName).value !== null) {
                let count = context.get(propName).count;
                statusText += propName + " (" + count + ")";
                if (i < inputProperties.length - 1) {
                    statusText += ", ";
                }
            }
        }
        node.status({ fill: "green", shape: "dot", text: statusText });

        msg.status = { fill: "red", shape: "dot", text: statusText };


    }

    // Set the status to "red" if there are no values in the context
    if (!hasContext) {
        node.status({ fill: "red", shape: "dot", text: "disconnected" });
    } else {
        // Set the status to "green" if there are values in the context
        let statusText = "";
        for (let i = 0; i < inputProperties.length; i++) {
            let propName = inputProperties[i];
