                let count = context.get(propName).count;
                statusText += propName + " (" + count + ")";
                if (i < inputProperties.length - 1) {
                    statusText += ", ";
                }
            }
        }
        node.status({ fill: "green", shape: "dot", text: statusText });

        msg.status = { fill: "green", shape: "dot", text: statusText };

    }

    // Do not pass the message to the function output if the input has not changed
    return null;
}

